public class EnKucuk {
  public static int enKucukBul(int[] dizi) {
    int enKucuk = dizi[0];
    for (int index = 1; index < dizi.length; index++) {
      if (dizi[index] < enKucuk) {
        enKucuk = dizi[index];
      }
    }
    return enKucuk;
  }

  public static void main(String[] args) {
    int[] sayilar = {8, 3, 15, 1, 9};
    int sonuc = enKucukBul(sayilar);
    System.out.println("En kucuk: " + sonuc);
  }
}

public class Faktoriyel {
  public static int faktoriyelHesapla(int sayi) {
    if (sayi <= 1) {
      return 1;
    }
    return sayi * faktoriyelHesapla(sayi - 1);
  }

  public static void main(String[] args) {
    int deger = 6;
    int sonuc = faktoriyelHesapla(deger);
    System.out.println(deger + "! = " + sonuc);
  }
}

public class HarfSay {
  public static int harfSayisiBul(String kelime, char aranan) {
    int sayac = 0;
    for (int index = 0; index < kelime.length(); index++) {
      if (kelime.charAt(index) == aranan) {
        sayac++;
      }
    }
    return sayac;
  }

  public static void main(String[] args) {
    String cumle = "programlama";
    char harf = 'a';
    int sonuc = harfSayisiBul(cumle, harf);
    System.out.println(harf + " harfi " + sonuc + " kere gecti");
  }
}

