public class DiziArama {
  public static int degerAra(int[] dizi, int aranan) {
    for (int index = 0; index < dizi.length; index++) {
      if (dizi[index] == aranan) {
        return index;
      }
    }
    return -1;
  }

  public static void main(String[] args) {
    int[] sayilar = {5, 12, 8, 21, 3};
    int arananDeger = 8;
    int sonuc = degerAra(sayilar, arananDeger);
    System.out.println(arananDeger + " degeri " + sonuc + " indexinde");
  }
}

public class Fibonacci {
  public static void fibonacciYazdir(int adet) {
    int sayi1 = 0, sayi2 = 1;
    System.out.print(sayi1 + " " + sayi2);
    for (int index = 2; index < adet; index++) {
      int sonraki = sayi1 + sayi2;
      System.out.print(" " + sonraki);
      sayi1 = sayi2;
      sayi2 = sonraki;
    }
    System.out.println();
  }

  public static void main(String[] args) {
    int terimSayisi = 8;
    fibonacciYazdir(terimSayisi);
  }
}

public class HarfCevir {
  public static String harfleriCevir(String kelime) {
    String sonuc = "";
    for (int index = 0; index < kelime.length(); index++) {
      char gecerli = kelime.charAt(index);
      if (Character.isUpperCase(gecerli)) {
        sonuc += Character.toLowerCase(gecerli);
      } else {
        sonuc += Character.toUpperCase(gecerli);
      }
    }
    return sonuc;
  }

  public static void main(String[] args) {
    String girdi = "Merhaba Dunya";
    String cikti = harfleriCevir(girdi);
    System.out.println(cikti);
  }
}

